import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

function HomePage() {
  const [videos, setVideos] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('http://localhost:8000/api/videos/')
      .then(response => {
        console.log('Загружено видео:', response.data);
        setVideos(response.data);
        setLoading(false);
      })
      .catch(error => {
        console.error('Ошибка загрузки видео:', error);
        setLoading(false);
      });
  }, []);

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '60vh' }}>
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: 48, marginBottom: 16 }}>🎬</div>
          <p>Загрузка видео...</p>
        </div>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: 1400, margin: '0 auto' }}>
      {/* Hero секция */}
      <div style={{
        textAlign: 'center',
        padding: '48px 32px',
        marginBottom: 32,
        background: '#fff',
        borderRadius: 16,
        boxShadow: '0 2px 8px rgba(0,0,0,0.04)'
      }}>
        <h1 style={{ fontSize: 'clamp(32px, 5vw, 48px)', fontWeight: 700, marginBottom: 12 }}>
          Видеоплатформа
        </h1>
        <p style={{ fontSize: 18, color: '#6c757d' }}>
          Смотрите, загружайте и делитесь видео
        </p>
      </div>

      {videos.length === 0 ? (
        <div style={{ textAlign: 'center', padding: 64, background: '#fff', borderRadius: 16 }}>
          <div style={{ fontSize: 64, marginBottom: 20 }}>📭</div>
          <p style={{ fontSize: 18, marginBottom: 24 }}>Пока нет видео</p>
          <Link to="/upload" style={{
            background: '#4361ee',
            color: 'white',
            padding: '12px 24px',
            borderRadius: 12,
            textDecoration: 'none'
          }}>
            + Загрузить первое видео
          </Link>
        </div>
      ) : (
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
          gap: 24
        }}>
          {videos.map(video => {
            // Формируем URL
            const videoUrl = `http://localhost:8000${video.video_file}`;
            const thumbnailUrl = video.thumbnail ? `http://localhost:8000${video.thumbnail}` : null;
            
            return (
              <Link 
                to={`/video/${video.id}`} 
                key={video.id} 
                style={{ textDecoration: 'none' }}
              >
                <div style={{
                  background: '#fff',
                  borderRadius: 12,
                  overflow: 'hidden',
                  boxShadow: '0 2px 8px rgba(0,0,0,0.04)',
                  transition: 'transform 0.2s, box-shadow 0.2s',
                  cursor: 'pointer'
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.transform = 'translateY(-4px)';
                  e.currentTarget.style.boxShadow = '0 8px 24px rgba(0,0,0,0.08)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.transform = 'translateY(0)';
                  e.currentTarget.style.boxShadow = '0 2px 8px rgba(0,0,0,0.04)';
                }}>
                  
                  {/* ПРЕВЬЮ - простое и надёжное решение */}
                  <div style={{
                    width: '100%',
                    aspectRatio: '16/9',
                    backgroundColor: '#1a1a2e',
                    overflow: 'hidden',
                    position: 'relative'
                  }}>
                    {thumbnailUrl ? (
                      <img 
                        src={thumbnailUrl}
                        alt={video.title}
                        style={{
                          width: '100%',
                          height: '100%',
                          objectFit: 'cover'
                        }}
                      />
                    ) : (
                      <video 
                        src={videoUrl}
                        style={{
                          width: '100%',
                          height: '100%',
                          objectFit: 'cover'
                        }}
                        muted
                        preload="metadata"
                      />
                    )}
                  </div>
                  
                  {/* Информация */}
                  <div style={{ padding: '12px 16px' }}>
                    <h3 style={{
                      fontSize: 16,
                      fontWeight: 600,
                      color: '#1a1a1a',
                      marginBottom: 6,
                      display: '-webkit-box',
                      WebkitLineClamp: 2,
                      WebkitBoxOrient: 'vertical',
                      overflow: 'hidden'
                    }}>
                      {video.title}
                    </h3>
                    <p style={{ fontSize: 13, color: '#6c757d', margin: 0 }}>
                      {video.uploaded_by_name || 'Аноним'} • {video.views || 0} просмотров
                    </p>
                  </div>
                </div>
              </Link>
            );
          })}
        </div>
      )}
    </div>
  );
}

export default HomePage;
